from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql

app = Flask(__name__)


def create_query(table: str, columns: list, condition: str):
    if not columns:
        columns = ['*']
    query = sql.SQL("SELECT {} from {} WHERE {}").format(
        sql.SQL(','.join(columns)),
        sql.Identifier(table),
        sql.SQL(condition)
    )
    return query


@app.route('/dynamicSQL', methods=['GET'])
def dynamic_sql():
    table = request.args.get('table')
    columns = request.args.getlist('columns')
    condition = request.args.get('condition')
    try:
        conn = psycopg2.connect(database="your_database_name", user='your_user_name',
                                password='your_password', host='127.0.0.1', port='5432')
        cur = conn.cursor()
        query = create_query(table, columns, condition)
        cur.execute(query)
        records = cur.fetchall()
        return jsonify(records), 200
    except (Exception, psycopg2.Error) as error:
        return str(error), 400


if __name__ == '__main__':
    app.run(debug=True)